// FootController) so a consumer can render the Setup / Controllers / Modifier
// screens, not just placeable blocks.
//
// VERSION-PINNED: layout variants/controls filtered to fw 17.01 (the editor's
// current firmware ceiling); the Amp block uses its fw-pinned layout variant.
// Pages with block-type or version variants are unioned so the layout covers
// every type on this fw.
/* eslint-disable */

/** One control on an editor page: editor label + parameter binding. */
export interface Fm9LayoutControl {
  /** Editor knob/widget caption (HTML entities decoded). */
  label: string;
  /** Catalog parameterName (the editor's own symbol). */
  paramName: string;
  /** Resolved wire paramId (join vs the device catalog), or null if unresolved. */
  paramId: number | null;
  /** Zero-based layout column, when the editor specifies one. */
  col?: number;
}

/** One editor page (tab) of a block: a name and its controls in order. */
export interface Fm9LayoutPage {
  /** Page/tab name as shown in the editor (e.g. 'Basic', 'Authentic'). */
  name: string;
  /** Controls on this page, editor order (decorative labels/spacers omitted). */
  controls: Fm9LayoutControl[];
}

/** A block's full editor layout: its pages/tabs. */
export interface Fm9BlockLayout {
  /** The block's editor display name (e.g. 'Reverb', 'Foot Controller'). */
  editorName: string;
  /** Editor pages (tabs) in display order. */
  pages: Fm9LayoutPage[];
}

